public List<KNodeTrain> kNodeTrainsPostProcess(@NotNull List<KNodeTrain> kNodeTrains, @NotNull ServiceWrapper serviceWrapper) {
    kNodeTrains = kNodeTrains.parallelStream().filter(kNodeTrain -> !kNodeTrain.isReset()).collect(Collectors.toList());
    var param = serviceWrapper.getParamObj(TrainDataDownSignalBalanceParam.class);
    int down = kNodeTrains.parallelStream().mapToInt(KNodeTrain::downSignal).sum();

    double currentRatio = (double) down / kNodeTrains.size();
    double thresholdRatio = 1 - param.getThreshold();

    if (currentRatio < thresholdRatio) {
        List<KNodeTrain> sorted = kNodeTrains.stream().filter(kNodeTrain -> !kNodeTrain.isDown())
                .sorted(Comparator.comparing(KNodeTrain::getFuturePercent)).collect(Collectors.toList());
        int removeCount = (int) Math.ceil((thresholdRatio - currentRatio) * kNodeTrains.size());
        for (int i = 0; i < removeCount && !sorted.isEmpty(); i++) {
            KNodeTrain kNodeTrainToRemove = sorted.remove(0);
            kNodeTrains.remove(kNodeTrainToRemove);
        }
    } else if (currentRatio > thresholdRatio) {
        List<KNodeTrain> sorted = kNodeTrains.stream().filter(KNodeTrain::isDown)
                .sorted(Comparator.comparing(KNodeTrain::getFuturePercent)).collect(Collectors.toList());
        int removeCount = (int) Math.ceil((currentRatio - thresholdRatio) * kNodeTrains.size());
        for (int i = 0; i < removeCount && !sorted.isEmpty(); i++) {
            KNodeTrain kNodeTrainToRemove = sorted.remove(0);
            kNodeTrains.remove(kNodeTrainToRemove);
        }
    }

    return kNodeTrains;
}
```

