public List<KNodeTrain> kNodeTrainsPostProcess(@NotNull List<KNodeTrain> kNodeTrains, @NotNull ServiceWrapper serviceWrapper) {
    // 使用并行流进行过滤
    kNodeTrains = kNodeTrains.parallelStream()
                             .filter(kNodeTrain -> !kNodeTrain.isReset())
                             .collect(Collectors.toList());

    var param = serviceWrapper.getParamObj(TrainDataDownSignalBalanceParam.class);
    int down = kNodeTrains.stream()
                          .mapToInt(KNodeTrain::downSignal)
                          .sum();

    double threshold = param.getThreshold();
    double currentRatio = (double) down / kNodeTrains.size();

    // 是否需要操作列表
    if (currentRatio != threshold) {
        // 根据上下信号选择过滤条件和计算移除元素的数量
        int requiredSignalCount = (int) Math.ceil(kNodeTrains.size() * threshold);
        boolean isDownAdjustment = currentRatio < threshold;
        int removeCount = isDownAdjustment ? down - requiredSignalCount : requiredSignalCount - down;

        // 根据过滤条件排序并选择对应子列表清除
        List<KNodeTrain> toAdjust = kNodeTrains.stream()
            .filter(kNodeTrain -> isDownAdjustment ? !kNodeTrain.isDown() : kNodeTrain.isDown())
            .sorted(Comparator.comparing(kNodeTrain -> Math.abs(kNodeTrain.getFuturePercent())))
            .collect(Collectors.toList());

        // 只有当需要移除的元素数量大于0时才进行操作
        if (removeCount > 0) {
            // 选取需要移除的子列表部分并清除之
            List<KNodeTrain> subListToRemove = toAdjust.subList(0, Math.min(toAdjust.size(), removeCount));
            kNodeTrains.removeAll(subListToRemove);
            subListToRemove.clear(); // 可选清除，不影响结果，仅作为列表操作示例
        }
    }

    return kNodeTrains;
}
```

